// Validate incoming notification payload
const payload = $input.first().json.body;

if (!payload.to || !payload.subject || !payload.message) {
  throw new Error('Missing required fields: to, subject, message');
}

return {
  to: payload.to,
  subject: payload.subject,
  message: payload.message,
  type: payload.type || 'email',
  lead_id: payload.lead_id || null,
  customer_name: payload.customer_name || null
};

// Log notification result
const result = $input.first().json;
const log = {
  workflow: 'Send Notification',
  action: 'notification_sent',
  to: $json.to,
  type: $json.type,
  status: result.accepted ? 'sent' : 'failed',
  timestamp: new Date().toISOString()
};
console.log('[NOTIFICATION]', JSON.stringify(log));

// Return success response
return {
  success: true,
  message_id: result.messageId || null,
  to: $json.to,
  subject: $json.subject
};

const error = $input.first().json.error || 'Notification failed';
console.error('[NOTIFICATION ERROR]', error.message || error);

// Fallback: log to console for monitoring
return {
  success: false,
  error: error.message || error,
  to: $json.to
};
